# Skeptic packet solve S44-T1-A-E2: three-route assess for contract gate
def assess(record: dict) -> str:
    required = {'matrix', 'supported', 'lint', 'types', 'tests', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (record["lint"] or record["types"] or record["tests"]) else 'FAIL_CI_GATE'

valid = {'case_id': 'CASO-PIU-044-1A', 'lint': True, 'types': True, 'tests': True, 'matrix': {'3.11', '3.12'}, 'supported': {'3.11', '3.12'}}
invalid = {'case_id': 'CASO-PIU-044-1A', 'lint': False, 'types': False, 'tests': False, 'matrix': {'3.11', '3.12'}, 'supported': {'3.11', '3.12'}}
incomplete = {**valid}
incomplete.pop('supported', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
assert results[0] == 'PASS' and results[2].startswith('MISSING'), results

